from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_oauthlib.provider import OAuth2Provider
import jwt

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///oauth.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(64), unique=True, nullable=False)
    password = db.Column(db.String(128), nullable=False)

class Client(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    client_id = db.Column(db.String(32), unique=True, nullable=False)
    client_secret = db.Column(db.String(255), nullable=False)

provider = OAuth2Provider(app, db=db)

@app.route('/token', methods=['POST'])
def issue_token():
    code = request.json.get('code')
    redirect_uri = request.json.get('redirect_uri')
    client_id = request.json.get('client_id')
    client_secret = request.json.get('client_secret')

    token = provider.create_access_token(code, redirect_uri, client_id, client_secret)
    return jsonify({'token': token})

@app.route('/validate', methods=['GET'])
@provider.require_oauth()
def validate():
    user_id = get_user_from_token(request.headers['Authorization'].split()[1])
    if user_id:
        return jsonify({'user_id': user_id})
    else:
        return jsonify({'error': 'Invalid token'}), 401

def get_user_from_token(token):
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload.get('user_id')
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None

@provider.require_oauth()
def require_oauth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers['Authorization'].split()[1]
        user_id = get_user_from_token(token)
        if user_id:
            return f(*args, **kwargs)
        else:
            return jsonify({'error': 'Invalid token'}), 401
    return decorated_function

if __name__ == '__main__':
    app.run(debug=True)